using System.Reflection; var asm = typeof(MediaBrowser.Controller.Entities.Video).Assembly; var type = typeof(MediaBrowser.Controller.Entities.Video); var prop = type.GetProperty("LinkedAlternateVersions"); if (prop == null) { Console.WriteLine("Property NOT FOUND on Video"); var all = type.GetProperties(BindingFlags.Public|BindingFlags.Instance); foreach (var p in all.Where(x => x.Name.Contains("Linked") || x.Name.Contains("Alternate"))) Console.WriteLine($"  Found: {p.DeclaringType!.Name}.{p.Name}"); } else { var g = prop.GetGetMethod()!; Console.WriteLine($"{prop.DeclaringType!.Name}.{prop.Name} Virtual={g.IsVirtual} Final={g.IsFinal} Abstract={g.IsAbstract}"); var s = prop.GetSetMethod(); Console.WriteLine($"  HasSetter={s!=null}"); if (s!=null) Console.WriteLine($"  SetterVirtual={s.IsVirtual}"); Console.WriteLine($"  PropertyType={prop.PropertyType}"); }
